    indicator: 'w-full h-full flex items-center justify-center text-current',
    'indicator-icon': 'size-full',
    label: ''
  },
  variants: {
    color: {
      primary: {
        control: `border-primary focus-visible:ring-primary/30 data-[state=checked]:bg-primary data-[state=checked]:text-primary-foreground data-[state=indeterminate]:bg-primary data-[state=indeterminate]:text-primary-foreground`
      },
      destructive: {
        control: `border-destructive focus-visible:ring-destructive/30 data-[state=checked]:bg-destructive data-[state=checked]:text-destructive-foreground data-[state=indeterminate]:bg-destructive data-[state=indeterminate]:text-destructive-foreground`
      },
      success: {
        control: `border-success focus-visible:ring-success/30 data-[state=checked]:bg-success data-[state=checked]:text-success-foreground data-[state=indeterminate]:bg-success data-[state=indeterminate]:text-success-foreground`
      },
      warning: {
        control: `border-warning focus-visible:ring-warning/30 data-[state=checked]:bg-warning data-[state=checked]:text-warning-foreground data-[state=indeterminate]:bg-warning data-[state=indeterminate]:text-warning-foreground`
      },
      info: {
        control: `border-info focus-visible:ring-info/30 data-[state=checked]:bg-info data-[state=checked]:text-info-foreground data-[state=indeterminate]:bg-info data-[state=indeterminate]:text-info-foreground`
      },
      carbon: {
        control: `border-carbon focus-visible:ring-carbon/30 data-[state=checked]:bg-carbon data-[state=checked]:text-carbon-foreground data-[state=indeterminate]:bg-carbon data-[state=indeterminate]:text-carbon-foreground`
      },
      secondary: {
        control: `border-secondary-foreground/50 focus-visible:ring-secondary-foreground/20 data-[state=checked]:bg-secondary-foreground/5 data-[state=checked]:text-secondary-foreground data-[state=indeterminate]:bg-secondary-foreground/5 data-[state=indeterminate]:text-secondary-foreground`
      },
      accent: {
        control: `border-accent-foreground/50 focus-visible:ring-accent-foreground/20 data-[state=checked]:bg-accent-foreground/5 data-[state=checked]:text-accent-foreground data-[state=indeterminate]:bg-accent-foreground/5 data-[state=indeterminate]:text-accent-foreground`
      }
    },
    size: {
      xs: {
        groupRoot: 'gap-x-2 gap-y-1.5',
        root: 'gap-1.5',
        control: 'size-3'
      },
      sm: {
        groupRoot: 'gap-x-2.5 gap-y-1.75',
        root: 'gap-1.75',
        control: 'size-3.5'
      },
      md: {
        groupRoot: 'gap-x-3 gap-y-2',
        root: 'gap-2',
        control: 'size-4'
      },
      lg: {
        groupRoot: 'gap-x-3.5 gap-y-2.5',
        root: 'gap-2.5',
        control: 'size-4.5'
      },
      xl: {
        groupRoot: 'gap-x-4 gap-y-3',
        root: 'gap-3',
        control: 'size-5'
      },
      '2xl': {
        groupRoot: 'gap-x-4.5 gap-y-3.5',
        root: 'gap-3.5',
        control: 'size-6'
      }
    },
    orientation: {
      horizontal: {
        groupRoot: 'items-center'
      },
      vertical: {
        groupRoot: 'flex-col'
      }
    },
    shape: {
      square: {
        control: 'rounded-sm'
      },
      rounded: {
        control: 'rounded-full'
      }
    }
  },
  defaultVariants: {
    color: 'primary',
    size: 'md',
    orientation: 'horizontal',
    shape: 'square'
  }
});

